mapper.select:
select count(*)
from service_review
where user_id=#{userId}
  and rating <= #{maxRating}

select coalesce(nullif(tags, ''), nullif(comment, ''), concat(rating, '分评价')) as reason
from service_review
where user_id=#{userId}
  and rating <= #{maxRating}
order by created_at desc, id desc
limit #{limit}
